  ('heelevel3-d0d1b9a2-moex-00369', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', '下列何者最不可能是關鍵查核事項？', '["重大匯兌損失", "導致會計師出具修正式意見之事項", "使受查者繼續經營能力具不確定性之事項", "重大非常規關係人交易"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:01+00:00", "source_pdf_sha1": "ebce2a12ce0a", "answer_pdf_sha1": "45ac4217f984", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00370', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', '審計準則700號（原審計準則公報第五十七號）「財務報表查核報告」就會計師對財務報表形成查 核意見之責任，以及其依查核結果所出具查核報告之格式及內容等均有規範。下列敘述何者錯誤？', '["查核報告應依案件之情況載明報告收受者", "於執行集團查核時，如涉及不同會計師職業道德規範，查核報告中通常提及集團查核團隊所適 用之會計師職業道德規範", "對適用之財務報導架構之說明，若包括不精確之描述或限制性文字（例如「財務報表大致遵循 XX準則」），則可能誤導財務報表使用者，因此非屬適當", "會計師對依照遵循架構編製之財務報表出具無保留意見之查核報告時，查核意見應敘明「依本 會計師之意見，上開財務報表在所有重大方面係依照[適用之財務報導架構]編製，足以允當表 達……」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:01+00:00", "source_pdf_sha1": "ebce2a12ce0a", "answer_pdf_sha1": "45ac4217f984", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00371', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', '下列那種情況會計師應出具無法表示意見之查核報告？', '["受查公司呆帳少估3億元，嚴重影響財務報表之允當表達", "受查公司帳冊遭火災焚毀，會計師執行其他替代查核程序亦無法取得足夠及適切之查核證據", "受查公司未揭露金額重大的法律訴訟案", "已決定清算之受查公司仍然用繼續經營之會計基礎編製財務報表"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:01+00:00", "source_pdf_sha1": "ebce2a12ce0a", "answer_pdf_sha1": "45ac4217f984", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00372', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', '下列有關會計師事務所為審計客戶提供非審計業務，何者不會影響獨立性？①依審計準則，為財', '["事務所關係企業提供審計客戶評價服務，且評價 結果將形成財務報表之一部分", "事務所派遣內部員工，協助審計客戶執行工作", "協助審計客 戶處理與稅捐機關之爭議", "僅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:01+00:00", "source_pdf_sha1": "ebce2a12ce0a", "answer_pdf_sha1": "45ac4217f984", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00373', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', '執行元額單位抽樣（MonetaryUnitSampling）時，若某一客戶的應收帳款帳載金額為$45,000，查 核後金額為$30,000，而抽樣間距為$30,000，預期錯誤金額為多少？', '["$10,000", "$15,000", "$20,000", "$30,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:01+00:00", "source_pdf_sha1": "ebce2a12ce0a", "answer_pdf_sha1": "45ac4217f984", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00374', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', '偵查舞弊的技巧及建立反舞弊程序與內部控制制度，大都基於舞弊三角（FraudTriangle）理論。 下列何者不是舞弊三角的要素？', '["心理狀態", "機會", "誘因及壓力", "態度或合理化"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:01+00:00", "source_pdf_sha1": "ebce2a12ce0a", "answer_pdf_sha1": "45ac4217f984", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL)
